"use client";

import React from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { LayoutDashboard, Wrench, Eye, Settings } from 'lucide-react';

const navItems = [
    { href: '/dashboard', label: 'Overview', icon: LayoutDashboard },
    { href: '/dashboard/tools', label: 'Manage Tools', icon: Wrench },
    { href: '/dashboard/visualizations', label: 'Visualization', icon: Eye },
    { href: '/dashboard/settings', label: 'Platform Settings', icon: Settings },
];

const Sidebar: React.FC = () => {
    const pathname = usePathname();

    return (
        <aside
            className="relative w-64 h-full overflow-hidden border-r border-white/10 text-white bg-fixed bg-cover bg-center bg-no-repeat"
            style={{ backgroundImage: "url('/header-dashboard.png')" }}
        >
            {/* Dark overlay */}
            <div className="absolute inset-0 bg-black/40" />

            {/* Content */}
            <nav className="relative z-10 p-4">
                <p className="mb-4 px-3 text-[10px] font-semibold uppercase tracking-widest text-white/40">
                    Navigation
                </p>
                <ul className="space-y-2">
                    {navItems.map(({ href, label, icon: Icon }) => {
                        const isActive = pathname === href;
                        return (
                            <li key={href}>
                                <Link
                                    href={href}
                                    className={`
                                        group flex items-center gap-3 rounded-xl px-4 py-3
                                        text-sm font-medium transition-all duration-200
                                        ${isActive
                                            ? 'bg-white/25 backdrop-blur-md border border-white/30 text-white shadow-lg shadow-white/5'
                                            : 'bg-white/10 backdrop-blur-sm border border-white/10 text-white/70 hover:bg-white/20 hover:text-white hover:border-white/20 hover:shadow-md hover:shadow-white/5'
                                        }
                                    `}
                                >
                                    <div className={`
                                        rounded-lg p-1.5 transition-colors duration-200
                                        ${isActive
                                            ? 'bg-white/20 text-white'
                                            : 'bg-white/5 text-white/50 group-hover:bg-white/15 group-hover:text-white'
                                        }
                                    `}>
                                        <Icon className="h-4 w-4" />
                                    </div>
                                    {label}
                                    {isActive && (
                                        <div className="ml-auto h-2 w-2 rounded-full bg-cyan-400 shadow-md shadow-cyan-400/50" />
                                    )}
                                </Link>
                            </li>
                        );
                    })}
                </ul>
            </nav>
        </aside>
    );
};

export default Sidebar;